export default [
  { term: '3DES', fullName: 'Triple Data Encryption Standard', definition: 'A symmetric encryption algorithm that applies the DES cipher three times to each data block, using two or three 56-bit keys for an effective key length of 112 or 168 bits. It was designed to extend the life of DES but is now considered deprecated due to its slow performance and vulnerability to meet-in-the-middle attacks.' },
  { term: '802.1X', fullName: 'IEEE 802.1X Port-Based Network Access Control', definition: 'An IEEE standard that provides port-based network access control, requiring devices to authenticate before gaining access to a LAN or WLAN. It is commonly used with RADIUS servers and EAP to enforce identity-based access policies in enterprise networks.' },
  { term: 'AAA', fullName: 'Authentication, Authorization, and Accounting', definition: 'A security framework that controls access to network resources by verifying identity (authentication), determining what resources a user can access (authorization), and tracking usage (accounting). It is foundational to network access control and is commonly implemented via RADIUS or TACACS+.' },
  { term: 'ABAC', fullName: 'Attribute-Based Access Control', definition: 'An access control model that grants permissions based on attributes of the user, resource, environment, and action rather than predefined roles. It provides fine-grained, dynamic access control suitable for complex environments where context matters.' },
  { term: 'ACL', fullName: 'Access Control List', definition: 'A set of rules that defines which users or system processes are granted or denied access to specific network resources or objects. ACLs are implemented on routers, firewalls, and operating systems to enforce traffic filtering and object-level permissions.' },
  { term: 'AES', fullName: 'Advanced Encryption Standard', definition: 'A symmetric block cipher adopted by NIST in 2001 that supports key lengths of 128, 192, or 256 bits and is widely used for encrypting data at rest and in transit. AES is considered highly secure and is the encryption standard for WPA2/WPA3 wireless networks and many VPN solutions.' },
  { term: 'AH', fullName: 'Authentication Header', definition: 'An IPSec protocol that provides data integrity, authentication, and anti-replay protection for IP packets but does not provide encryption. AH is used to verify that packet contents have not been tampered with during transit.' },
  { term: 'AI', fullName: 'Artificial Intelligence', definition: 'The simulation of human intelligence processes by computer systems, including learning, reasoning, and self-correction. In cybersecurity, AI is used for threat detection, anomaly detection, and automating security operations.' },
  { term: 'AIS', fullName: 'Automated Indicator Sharing', definition: 'A CISA initiative that enables real-time exchange of cyber threat indicators and defensive measures between the federal government and private sector. AIS uses the STIX and TAXII standards to automate the sharing of threat intelligence.' },
  { term: 'ALE', fullName: 'Annualized Loss Expectancy', definition: 'A quantitative risk metric that estimates the expected monetary loss from a specific threat over a one-year period, calculated by multiplying the Single Loss Expectancy (SLE) by the Annual Rate of Occurrence (ARO). ALE helps organizations prioritize security investments based on potential financial impact.' },
  { term: 'APT', fullName: 'Advanced Persistent Threat', definition: 'A sophisticated, long-term cyberattack campaign typically carried out by nation-state actors or well-funded criminal groups who gain unauthorized access to a network and remain undetected for extended periods. APTs aim to steal data, conduct espionage, or position themselves for future attacks rather than causing immediate disruption.' },
  { term: 'API', fullName: 'Application Programming Interface', definition: 'A set of defined rules and protocols that enables different software applications to communicate and exchange data with each other. From a security perspective, APIs must be secured against threats like injection attacks, broken authentication, and excessive data exposure as defined by the OWASP API Security Top 10.' },
  { term: 'ARO', fullName: 'Annual Rate of Occurrence', definition: 'A quantitative risk metric that represents how many times a specific threat is expected to occur within a one-year period. ARO is used alongside SLE to calculate ALE and helps organizations understand the frequency of potential security incidents.' },
  { term: 'ARP', fullName: 'Address Resolution Protocol', definition: 'A network protocol used to map IP addresses to MAC addresses within a local network segment. ARP is vulnerable to spoofing attacks (ARP poisoning) where an attacker sends fake ARP replies to redirect traffic through a malicious host, enabling man-in-the-middle attacks.' },
  { term: 'ASLR', fullName: 'Address Space Layout Randomization', definition: 'A memory protection technique that randomly arranges the address space positions of key data areas of a process, including the base of the executable, stack, heap, and libraries. ASLR makes it more difficult for attackers to exploit memory corruption vulnerabilities by making addresses unpredictable.' },
  { term: 'ATT&CK', fullName: 'Adversarial Tactics, Techniques, and Common Knowledge', definition: 'The MITRE ATT&CK framework is a globally accessible knowledge base of adversary tactics and techniques based on real-world observations. Security teams use it to understand how attackers operate, improve threat detection, and assess their defensive capabilities.' },
  { term: 'BCP', fullName: 'Business Continuity Plan', definition: 'A documented strategy that outlines how an organization will continue operating during and after a disaster or disruptive event. BCP encompasses risk assessment, recovery strategies, and tested procedures to ensure critical business functions remain available.' },
  { term: 'BGP', fullName: 'Border Gateway Protocol', definition: 'The routing protocol that manages how packets are routed across the internet between autonomous systems. BGP hijacking is a significant security threat where attackers manipulate routing tables to redirect internet traffic through malicious infrastructure.' },
  { term: 'BIOS', fullName: 'Basic Input/Output System', definition: 'Firmware stored on a chip on the motherboard that initializes hardware during the boot process and provides runtime services for the operating system. BIOS security is critical as compromised firmware can persist through OS reinstalls and is difficult to detect.' },
  { term: 'BYOD', fullName: 'Bring Your Own Device', definition: 'A policy that allows employees to use their personal devices such as smartphones, tablets, and laptops for work purposes. BYOD introduces security challenges including data leakage, inadequate patching, and difficulty enforcing security policies on personal devices.' },
  { term: 'CA', fullName: 'Certificate Authority', definition: 'A trusted entity in a PKI that issues, manages, and revokes digital certificates, binding public keys to the identities of certificate holders. CAs are the foundation of trust in public-key cryptography, and a compromised CA can undermine security across all systems relying on its certificates.' },
  { term: 'CASB', fullName: 'Cloud Access Security Broker', definition: 'A security policy enforcement point placed between cloud service consumers and providers to enforce enterprise security policies as cloud-based resources are accessed. CASBs provide visibility, compliance, data security, and threat protection for cloud services.' },
  { term: 'CAPTCHA', fullName: 'Completely Automated Public Turing test to tell Computers and Humans Apart', definition: 'A challenge-response test used to determine whether a user is human or an automated bot, typically requiring image recognition or text entry. CAPTCHAs protect web applications from automated abuse such as credential stuffing, spam, and scraping.' },
  { term: 'CBC', fullName: 'Cipher Block Chaining', definition: 'A block cipher mode of operation where each plaintext block is XORed with the previous ciphertext block before encryption, creating a dependency chain. CBC provides better security than ECB mode but is vulnerable to padding oracle attacks if not implemented correctly.' },
  { term: 'CDN', fullName: 'Content Delivery Network', definition: 'A geographically distributed network of servers that delivers web content to users from the server closest to them, improving performance and availability. CDNs can also provide security benefits such as DDoS mitigation, WAF capabilities, and TLS termination.' },
  { term: 'CHAP', fullName: 'Challenge Handshake Authentication Protocol', definition: 'An authentication protocol that uses a three-way handshake and hashed responses to verify identity without transmitting the password in cleartext. CHAP periodically re-authenticates during a session, providing protection against replay attacks.' },
  { term: 'CI/CD', fullName: 'Continuous Integration/Continuous Delivery', definition: 'A software development practice where code changes are automatically built, tested, and deployed to production environments frequently. Securing the CI/CD pipeline is critical as it represents a high-value attack surface that, if compromised, can lead to supply chain attacks.' },
  { term: 'CIS', fullName: 'Center for Internet Security', definition: 'A nonprofit organization that develops best practices and guidelines for securing IT systems through its CIS Controls and CIS Benchmarks. CIS Controls provide a prioritized set of security actions organizations can take to reduce their attack surface and improve their security posture.' },
  { term: 'CIRT', fullName: 'Computer Incident Response Team', definition: 'A group of security professionals responsible for responding to, analyzing, and recovering from cybersecurity incidents within an organization. CIRTs coordinate the technical and organizational response to security breaches to minimize damage and restore normal operations.' },
  { term: 'CMMC', fullName: 'Cybersecurity Maturity Model Certification', definition: 'A US Department of Defense framework that establishes cybersecurity standards and practices for defense contractors handling Controlled Unclassified Information (CUI). CMMC requires third-party assessments to verify compliance at different maturity levels.' },
  { term: 'COOP', fullName: 'Continuity of Operations Plan', definition: 'A government-focused plan that ensures the continuation of essential functions during a wide range of emergencies. COOP addresses succession of leadership, delegation of authority, and alternative facilities to maintain operations during disruptions.' },
  { term: 'COPPA', fullName: "Children's Online Privacy Protection Act", definition: "A US federal law that imposes requirements on operators of websites or online services directed to children under 13 years old regarding the collection and use of personal information. Non-compliance can result in significant fines and reputational damage." },
  { term: 'COTS', fullName: 'Commercial Off-The-Shelf', definition: 'Software or hardware products that are commercially available and ready-made for the general public rather than custom-built for a specific organization. COTS products require careful patch management and configuration hardening as their widespread use makes them common attack targets.' },
  { term: 'CRL', fullName: 'Certificate Revocation List', definition: 'A digitally signed list maintained by a Certificate Authority that contains certificates that have been revoked before their expiration date. Systems check the CRL to verify that a certificate is still valid and has not been revoked due to compromise or policy violation.' },
  { term: 'CSRF', fullName: 'Cross-Site Request Forgery', definition: 'A web attack that tricks an authenticated user into unknowingly submitting a malicious request to a web application in which they are currently authenticated. CSRF exploits the trust a website has in a user\'s browser and can be mitigated using anti-CSRF tokens, SameSite cookies, and double-submit cookie patterns.' },
  { term: 'CSP', fullName: 'Cloud Service Provider', definition: 'A company that offers cloud computing services including infrastructure, platforms, and software delivered over the internet. Organizations using CSPs must understand the shared responsibility model to ensure appropriate security controls are in place.' },
  { term: 'CSR', fullName: 'Certificate Signing Request', definition: 'A block of encoded text that is generated on the server where the certificate will be installed and contains information about the organization and the public key to be included in the certificate. The CSR is submitted to a CA, which uses it to create and sign a digital certificate.' },
  { term: 'CTI', fullName: 'Cyber Threat Intelligence', definition: 'Evidence-based knowledge about existing or emerging threats to assets, including context, mechanisms, indicators, implications, and actionable advice. CTI helps organizations make informed decisions about their defenses and prioritize security investments.' },
  { term: 'CVE', fullName: 'Common Vulnerabilities and Exposures', definition: 'A public dictionary of standardized identifiers for known cybersecurity vulnerabilities, maintained by MITRE Corporation. CVE IDs allow security professionals to quickly identify and reference specific vulnerabilities when patching systems or communicating about threats.' },
  { term: 'CVSS', fullName: 'Common Vulnerability Scoring System', definition: 'An open industry standard for assessing the severity of computer system security vulnerabilities using a numerical score from 0 to 10. CVSS scores help organizations prioritize vulnerability remediation efforts based on factors like exploitability, impact, and environmental context.' },
  { term: 'DAC', fullName: 'Discretionary Access Control', definition: 'An access control model where the owner of a resource has the discretion to grant or restrict access to that resource for other users. DAC is flexible but can lead to privilege creep and is less suitable for environments requiring strict, centrally managed access policies.' },
  { term: 'DDoS', fullName: 'Distributed Denial of Service', definition: 'An attack that uses multiple compromised systems (often a botnet) to flood a target with traffic or requests, overwhelming its capacity and making it unavailable to legitimate users. DDoS attacks are mitigated through traffic scrubbing, rate limiting, CDN services, and ISP-level filtering.' },
  { term: 'DEP', fullName: 'Data Execution Prevention', definition: 'A security feature that marks certain memory regions as non-executable, preventing code from running in those regions such as the stack and heap. DEP helps prevent exploitation of buffer overflow vulnerabilities by stopping attackers from executing injected shellcode in data memory regions.' },
  { term: 'DHE', fullName: 'Diffie-Hellman Ephemeral', definition: 'A key exchange protocol variant that generates a fresh, temporary key pair for each session rather than reusing long-term keys. DHE provides Perfect Forward Secrecy, ensuring that compromise of long-term keys cannot expose past session traffic. ECDHE (Elliptic Curve DHE) is the more efficient variant and is mandatory in TLS 1.3.' },
  { term: 'DHCP', fullName: 'Dynamic Host Configuration Protocol', definition: 'A network protocol that automatically assigns IP addresses and other network configuration parameters to devices on a network. DHCP is vulnerable to rogue DHCP server attacks (DHCP spoofing), where an attacker replies to DHCP requests with malicious configuration data including a rogue gateway — mitigated by DHCP snooping on managed switches.' },
  { term: 'DES', fullName: 'Data Encryption Standard', definition: 'A symmetric block cipher that uses a 56-bit key to encrypt 64-bit blocks of data, standardized by NIST in 1977. DES is now considered obsolete and insecure due to its short key length, which makes it vulnerable to brute-force attacks, and has been replaced by AES.' },
  { term: 'DFIR', fullName: 'Digital Forensics and Incident Response', definition: 'A specialized field combining the collection and analysis of digital evidence with the structured response to cybersecurity incidents. DFIR practitioners preserve the chain of custody for digital evidence while simultaneously working to contain and eradicate threats.' },
  { term: 'DLP', fullName: 'Data Loss Prevention', definition: 'A set of tools and processes designed to detect and prevent unauthorized transmission, use, or storage of sensitive data such as PII, financial information, or intellectual property. DLP solutions monitor data in use, in motion, and at rest to enforce data handling policies.' },
  { term: 'DMZ', fullName: 'Demilitarized Zone', definition: 'A physical or logical subnetwork that sits between an organization\'s internal trusted network and an untrusted external network such as the internet. The DMZ hosts public-facing services like web servers and email gateways while isolating them from the internal network to limit the blast radius of a breach.' },
  { term: 'DNS', fullName: 'Domain Name System', definition: 'The internet\'s hierarchical naming system that translates human-readable domain names into IP addresses. DNS is a common attack vector for cache poisoning, hijacking, and tunneling attacks, making DNSSEC and DNS monitoring critical security controls.' },
  { term: 'DNSSEC', fullName: 'Domain Name System Security Extensions', definition: 'A suite of extensions to DNS that add cryptographic signatures to DNS records, allowing resolvers to verify that DNS responses are authentic and have not been tampered with. DNSSEC protects against DNS cache poisoning and spoofing attacks.' },
  { term: 'DoS', fullName: 'Denial of Service', definition: 'An attack that attempts to make a system, service, or network resource unavailable to its intended users by overwhelming it with requests or exploiting vulnerabilities. Unlike DDoS, a DoS attack originates from a single source and is generally easier to block.' },
  { term: 'DR', fullName: 'Disaster Recovery', definition: 'The set of policies, tools, and procedures to enable the recovery or continuation of vital technology infrastructure and systems following a natural or human-induced disaster. DR planning includes defining RTO and RPO objectives and regularly testing recovery procedures.' },
  { term: 'DRM', fullName: 'Digital Rights Management', definition: 'Technologies used to control access to and use of digital content and prevent unauthorized copying, sharing, or modification of copyrighted material. DRM is a form of data protection that enforces licensing terms and intellectual property rights.' },
  { term: 'DRP', fullName: 'Disaster Recovery Plan', definition: 'The IT-focused component of a Business Continuity Plan that defines procedures for restoring technology systems and data after a disaster. A DRP specifies which systems are restored first, in what order, and by whom, and is governed by RTO (recovery time) and RPO (recovery data loss) objectives.' },
  { term: 'DTLS', fullName: 'Datagram Transport Layer Security', definition: 'A protocol based on TLS that provides security for datagram-based applications, maintaining the connectionless nature of UDP while adding authentication and encryption. DTLS is used in applications like VPNs, VoIP, and gaming where UDP performance is required with TLS-level security.' },
  { term: 'EAP', fullName: 'Extensible Authentication Protocol', definition: 'An authentication framework commonly used in network access that supports multiple authentication methods including passwords, certificates, and tokens. EAP is used with 802.1X for wired and wireless network authentication and supports various inner methods like EAP-TLS, PEAP, and EAP-TTLS.' },
  { term: 'ECDSA', fullName: 'Elliptic Curve Digital Signature Algorithm', definition: 'A digital signature algorithm using elliptic curve cryptography that provides smaller, faster signatures than traditional DSA or RSA while maintaining equivalent security strength. ECDSA with 256-bit keys is widely used in TLS certificates, code signing, and blockchain systems.' },
  { term: 'EAP-TLS', fullName: 'Extensible Authentication Protocol - Transport Layer Security', definition: 'The most secure form of EAP that uses mutual certificate-based authentication, requiring both the client and the authentication server to present valid digital certificates. EAP-TLS is considered the gold standard for wireless authentication but requires a robust PKI infrastructure.' },
  { term: 'ECC', fullName: 'Elliptic Curve Cryptography', definition: 'A public-key cryptography approach based on the algebraic structure of elliptic curves over finite fields that provides equivalent security to RSA with much smaller key sizes. ECC\'s efficiency makes it ideal for mobile devices and IoT where computational resources and battery life are limited.' },
  { term: 'ECDHE', fullName: 'Elliptic Curve Diffie-Hellman Ephemeral', definition: 'A key agreement protocol that uses elliptic curve cryptography to establish a shared secret over an insecure channel, with ephemeral keys generated for each session. ECDHE provides perfect forward secrecy, ensuring that compromising a long-term private key does not expose past session keys.' },
  { term: 'EDR', fullName: 'Endpoint Detection and Response', definition: 'A security solution that continuously monitors endpoint devices to detect and respond to threats such as malware, ransomware, and fileless attacks in real time. EDR tools record endpoint activity and use behavioral analysis to identify suspicious patterns that traditional antivirus may miss.' },
  { term: 'EMM', fullName: 'Enterprise Mobility Management', definition: 'A set of tools and processes used to secure and manage mobile devices, applications, and content in enterprise environments. EMM encompasses MDM, MAM, and MCM capabilities to provide comprehensive control over how corporate data is accessed on mobile devices.' },
  { term: 'ESP', fullName: 'Encapsulating Security Payload', definition: 'An IPSec protocol that provides confidentiality, data origin authentication, connectionless integrity, anti-replay protection, and limited traffic-flow confidentiality. ESP can encrypt the payload alone or both the header and payload depending on the tunnel mode used.' },
  { term: 'FaaS', fullName: 'Function as a Service', definition: 'A cloud computing model where developers deploy individual functions that are executed in response to events without managing the underlying infrastructure. FaaS security concerns include function permissions, insecure dependencies, and inadequate logging and monitoring.' },
  { term: 'FAR', fullName: 'False Acceptance Rate', definition: 'A biometric system error rate measuring how often the system incorrectly grants access to an unauthorized user. A lower FAR means fewer unauthorized users are accepted but typically increases the False Rejection Rate (FRR). The crossover error rate (CER/EER) where FAR equals FRR indicates overall biometric system accuracy.' },
  { term: 'FRR', fullName: 'False Rejection Rate', definition: 'A biometric system error rate measuring how often the system incorrectly denies access to an authorized user. A lower FRR improves user experience but typically increases the False Acceptance Rate (FAR). The crossover error rate (CER) where FRR equals FAR is used to compare biometric system accuracy.' },
  { term: 'FDE', fullName: 'Full Disk Encryption', definition: 'A security method that encrypts all data on a storage device at the hardware or software level, making it unreadable without the proper authentication credentials or decryption key. FDE protects data at rest on lost or stolen devices and is a key control for mobile devices and laptops.' },
  { term: 'FedRAMP', fullName: 'Federal Risk and Authorization Management Program', definition: 'A US government program that provides a standardized approach to security assessment, authorization, and continuous monitoring for cloud products and services used by federal agencies. FedRAMP authorization demonstrates that a CSP meets rigorous federal security requirements based on NIST SP 800-53.' },
  { term: 'FERPA', fullName: 'Family Educational Rights and Privacy Act', definition: 'A US federal law that protects the privacy of student education records and gives parents and eligible students rights to access and control those records. Educational institutions that receive federal funding must comply with FERPA or risk losing that funding.' },
  { term: 'FIM', fullName: 'File Integrity Monitoring', definition: 'A security control that monitors and detects changes to critical system files, configuration files, and application files that could indicate a compromise or unauthorized modification. FIM compares current file states against known-good baselines and alerts when deviations are detected.' },
  { term: 'FISMA', fullName: 'Federal Information Security Management Act', definition: 'A US law that defines a comprehensive framework for securing federal government information systems, requiring agencies to develop, document, and implement information security programs. FISMA mandates annual security reviews and reporting to ensure federal systems meet NIST security standards.' },
  { term: 'GDPR', fullName: 'General Data Protection Regulation', definition: 'A European Union regulation that establishes comprehensive data protection requirements for organizations handling personal data of EU residents, including rights to access, erasure, and portability. GDPR imposes significant fines of up to 4% of global annual turnover for non-compliance.' },
  { term: 'GPG', fullName: 'GNU Privacy Guard', definition: 'A free and open-source implementation of the OpenPGP standard that provides encryption and digital signature capabilities for files and email. GPG is commonly used for verifying the integrity of software downloads and securing email communications.' },
  { term: 'HIPAA', fullName: 'Health Insurance Portability and Accountability Act', definition: 'A US law that establishes national standards for protecting sensitive patient health information (PHI) and requires appropriate administrative, physical, and technical safeguards. HIPAA violations can result in civil and criminal penalties ranging from $100 to $1.9 million per violation category per year.' },
  { term: 'HIPS', fullName: 'Host-based Intrusion Prevention System', definition: 'A security application installed on individual hosts that monitors system activity and blocks malicious behavior in real time. HIPS can detect and prevent attacks that bypass perimeter defenses by monitoring local processes, file access, network connections, and system calls.' },
  { term: 'HMAC', fullName: 'Hash-based Message Authentication Code', definition: 'A specific construction for creating a message authentication code using a cryptographic hash function in combination with a secret key, providing both data integrity and authentication. HMAC is used in protocols like TLS, IPSec, and JWT to verify that messages have not been altered and come from an authenticated source.' },
  { term: 'HSM', fullName: 'Hardware Security Module', definition: 'A physical computing device that safeguards and manages digital keys, performs encryption and decryption functions, and provides tamper-evident key storage. HSMs are used to protect high-value cryptographic operations and are required in many compliance frameworks for key management.' },
  { term: 'HTTP', fullName: 'Hypertext Transfer Protocol', definition: 'The foundational protocol for data communication on the World Wide Web that defines how messages are formatted and transmitted. HTTP transmits data in cleartext, making it vulnerable to eavesdropping and man-in-the-middle attacks, which is why HTTPS (HTTP over TLS) should be used for all sensitive communications.' },
  { term: 'HTTPS', fullName: 'Hypertext Transfer Protocol Secure', definition: 'An extension of HTTP that uses TLS to encrypt communications between a web browser and a web server, providing confidentiality, integrity, and authentication. HTTPS is essential for protecting login credentials, financial transactions, and any sensitive data transmitted over the web.' },
  { term: 'IaaS', fullName: 'Infrastructure as a Service', definition: 'A cloud computing model where virtualized computing resources such as servers, storage, and networking are provided over the internet on a pay-per-use basis. In IaaS, the customer is responsible for securing the operating system, applications, and data, while the provider secures the underlying infrastructure.' },
  { term: 'IAM', fullName: 'Identity and Access Management', definition: 'A framework of policies, processes, and technologies that ensures the right individuals access the right resources at the right times for the right reasons. IAM encompasses authentication, authorization, user provisioning, and governance to enforce least privilege and prevent unauthorized access.' },
  { term: 'IDOR', fullName: 'Insecure Direct Object Reference', definition: 'A web application vulnerability where an application exposes a reference to an internal implementation object (such as a database ID) in a URL or parameter, allowing attackers to manipulate these references to access unauthorized data. IDOR is prevented through proper authorization checks on every access to objects.' },
  { term: 'IDS', fullName: 'Intrusion Detection System', definition: 'A security system that monitors network traffic or host activities for suspicious patterns and known attack signatures, generating alerts when potential threats are detected. Unlike IPS, an IDS is passive and only detects and reports threats without actively blocking them.' },
  { term: 'IKE', fullName: 'Internet Key Exchange', definition: 'A protocol used to set up a security association (SA) in the IPSec protocol suite, handling the negotiation of cryptographic algorithms and the exchange of session keys. IKEv2 is the current standard and provides improved security, reliability, and support for NAT traversal compared to IKEv1.' },
  { term: 'IoA', fullName: 'Indicator of Attack', definition: 'Evidence of an ongoing or imminent cyberattack, focusing on attacker behaviors and tactics rather than specific malware signatures. IoAs enable proactive detection of attacks even when specific malware is unknown or zero-day exploits are used.' },
  { term: 'IoC', fullName: 'Indicator of Compromise', definition: 'Artifacts observed on a network or in an operating system that indicate with high confidence that a system has been breached. IoCs include malicious IP addresses, domain names, file hashes, and registry keys that are used to detect and investigate security incidents.' },
  { term: 'IoT', fullName: 'Internet of Things', definition: 'The network of physical devices embedded with sensors, software, and connectivity that enables them to collect and exchange data over the internet. IoT devices often have limited security capabilities, weak default credentials, and infrequent patching, making them common targets and entry points for attackers.' },
  { term: 'IPS', fullName: 'Intrusion Prevention System', definition: 'An active security system that monitors network traffic for malicious activity and automatically takes action to block or prevent detected threats. IPS is deployed inline in the network traffic path and can drop malicious packets, reset connections, or block source IP addresses.' },
  { term: 'IPSec', fullName: 'Internet Protocol Security', definition: 'A suite of protocols that provides authentication, integrity, and encryption for IP communications at the network layer, commonly used in VPN implementations. IPSec operates in transport mode (protecting the payload) or tunnel mode (protecting the entire packet) and uses AH and ESP protocols.' },
  { term: 'IR', fullName: 'Incident Response', definition: 'An organized approach to addressing and managing the aftermath of a security breach or cyberattack, following phases of preparation, identification, containment, eradication, recovery, and lessons learned. Effective IR minimizes damage, reduces recovery time and costs, and improves future defenses.' },
  { term: 'ITAR', fullName: 'International Traffic in Arms Regulations', definition: 'US regulations that control the export and import of defense-related articles and services on the US Munitions List, including certain encryption technologies. Organizations handling ITAR-controlled information must implement strict access controls and data handling procedures to prevent unauthorized disclosure.' },
  { term: 'IV', fullName: 'Initialization Vector', definition: 'A random or pseudo-random value used in combination with a secret key to initialize a cipher, ensuring that identical plaintext produces different ciphertext each time. Weak or reused IVs are a critical vulnerability, as demonstrated by the WEP protocol\'s susceptibility to IV-based attacks.' },
  { term: 'JIT', fullName: 'Just-In-Time', definition: 'An access provisioning approach where privileged access is granted only when needed and automatically revoked after a defined period or task completion. JIT access reduces the attack surface by ensuring that privileged accounts do not persistently exist and are therefore unavailable for attackers to compromise.' },
  { term: 'JIT', fullName: 'Just-in-Time Access', definition: 'An access provisioning model that grants elevated privileges only for a defined, limited time window when needed and automatically revokes them upon completion or expiration. JIT access eliminates standing privileges that persistently exist and are attractive targets for attackers, reducing the attack surface for privileged account compromise.' },
  { term: 'JSON', fullName: 'JavaScript Object Notation', definition: 'A lightweight, human-readable data interchange format widely used in REST APIs and web applications to structure data as key-value pairs and arrays. JSON is a common target for injection attacks; applications must validate and sanitize JSON input to prevent JSON injection and schema manipulation attacks.' },
  { term: 'JWT', fullName: 'JSON Web Token', definition: 'A compact, URL-safe token format used to represent claims between two parties, commonly used for authentication and authorization in web applications and APIs. JWT security depends on proper signature validation, use of strong algorithms, and secure storage, as tokens are often targeted in web attacks.' },
  { term: 'KDC', fullName: 'Key Distribution Center', definition: 'A component of the Kerberos authentication protocol that consists of an Authentication Server and Ticket Granting Server, responsible for issuing tickets that allow users to access network services. A compromised KDC can undermine the entire Kerberos trust model, making it a high-value target.' },
  { term: 'LDAP', fullName: 'Lightweight Directory Access Protocol', definition: 'A protocol for accessing and maintaining distributed directory information services over an IP network, commonly used for user authentication and authorization against directory services like Active Directory. LDAP injection is a significant vulnerability when user input is used in LDAP queries without proper sanitization.' },
  { term: 'LFI', fullName: 'Local File Inclusion', definition: 'A web application vulnerability that allows an attacker to include files from the server\'s local filesystem in the response, potentially exposing sensitive configuration files or allowing code execution. LFI is prevented through input validation, avoiding user-controlled paths, and implementing proper file access controls.' },
  { term: 'MAC', fullName: 'Mandatory Access Control', definition: 'An access control model where the operating system enforces access policies based on security labels assigned to subjects (users) and objects (resources) by a central authority. MAC is used in high-security environments like government systems where strict separation of classified information is required.' },
  { term: 'MAC', fullName: 'Media Access Control', definition: 'A unique hardware identifier assigned to a network interface card (NIC) at the manufacturer level, used for communication within a local network segment. MAC addresses can be spoofed, making MAC-based access controls alone insufficient as a security measure.' },
  { term: 'MAM', fullName: 'Mobile Application Management', definition: 'A subset of EMM that focuses on managing and securing mobile applications on employee devices rather than the entire device. MAM allows organizations to control corporate apps and data without requiring full device management, making it more suitable for BYOD environments.' },
  { term: 'MBR', fullName: 'Master Boot Record', definition: 'The first sector of a storage device that contains the bootloader and partition table, read by the BIOS during system startup. MBR rootkits infect this sector to execute malicious code before the operating system loads, making them difficult to detect and remove.' },
  { term: 'MTBF', fullName: 'Mean Time Between Failures', definition: 'A reliability metric representing the average time a component or system operates between failures. Higher MTBF indicates greater reliability. Organizations use MTBF alongside MTTR to make decisions about redundancy investments — components with low MTBF and high MTTR are prime candidates for redundancy.' },
  { term: 'MTTD', fullName: 'Mean Time to Detect', definition: 'The average time elapsed between the start of a cyberattack and its detection by the security team. Reducing MTTD limits attacker dwell time and potential damage. Improvements come from better detection tooling, threat hunting, tuned SIEM correlation rules, and enhanced threat intelligence.' },
  { term: 'MTTR', fullName: 'Mean Time to Respond', definition: 'The average time taken to contain and remediate a security incident after detection. MTTR measures IR team effectiveness. Automation through SOAR, well-tested playbooks, and trained IR teams reduce MTTR. Both MTTD and MTTR are key SOC performance metrics.' },
  { term: 'MTR', fullName: 'Mean Time to Repair', definition: 'The average time required to repair a failed component and restore it to operational status. MTR (also written MTTR) measures repairability and maintainability of systems. Lower MTR requires good spare-parts inventory, trained staff, and clear maintenance procedures.' },
  { term: 'MD5', fullName: 'Message Digest 5', definition: 'A widely used cryptographic hash function that produces a 128-bit hash value, now considered cryptographically broken due to discovered collision vulnerabilities. MD5 should not be used for security-sensitive purposes like digital signatures or password hashing, but may still be used for non-security file integrity checks.' },
  { term: 'MDM', fullName: 'Mobile Device Management', definition: 'Software that allows IT administrators to remotely manage, monitor, and secure mobile devices used in an organization. MDM enables enforcement of security policies such as encryption, screen lock, remote wipe, and application control on company and employee-owned devices.' },
  { term: 'MDR', fullName: 'Managed Detection and Response', definition: 'A managed security service that provides threat hunting, monitoring, and incident response capabilities through a combination of technology and human expertise. MDR providers act as an extension of an organization\'s security team, providing 24/7 monitoring and rapid response to threats.' },
  { term: 'MFA', fullName: 'Multi-Factor Authentication', definition: 'An authentication method that requires users to provide two or more verification factors from different categories: something you know, something you have, and something you are. MFA significantly reduces the risk of account compromise even when passwords are stolen, as attackers would also need to bypass additional factors.' },
  { term: 'MITRE ATT&CK', fullName: 'MITRE Adversarial Tactics, Techniques, and Common Knowledge', definition: 'A globally accessible knowledge base of adversary tactics and techniques based on real-world observations, organized into a matrix of attack phases from initial access to exfiltration. Security teams use the MITRE ATT&CK framework to improve threat detection capabilities, conduct red team exercises, and assess defensive coverage.' },
  { term: 'MOU', fullName: 'Memorandum of Understanding', definition: 'A non-binding agreement between two or more parties that outlines the terms and details of an understanding, including each party\'s requirements and responsibilities. MOUs are used in cybersecurity to establish expectations for information sharing, interconnection of systems, and incident response cooperation.' },
  { term: 'MPLS', fullName: 'Multiprotocol Label Switching', definition: 'A high-performance routing technique that directs data from one node to the next based on short path labels rather than long network addresses. MPLS VPNs provide secure, private network connectivity between sites but require trust in the service provider\'s security controls.' },
  { term: 'MSP', fullName: 'Managed Service Provider', definition: 'A company that remotely manages a customer\'s IT infrastructure and end-user systems under a subscription model. MSPs represent a significant supply chain risk, as a compromised MSP can provide attackers with access to multiple client organizations simultaneously.' },
  { term: 'MSLA', fullName: 'Master Service Level Agreement', definition: 'A comprehensive contract that establishes the overall terms and conditions governing service delivery between a provider and customer, with individual SLAs covering specific services. MSLAs should include security requirements, incident notification timelines, and audit rights.' },
  { term: 'MSSP', fullName: 'Managed Security Service Provider', definition: 'A service provider that offers outsourced monitoring and management of security devices and systems such as firewalls, IDS/IPS, and SIEM solutions. MSSPs provide organizations with access to security expertise and 24/7 monitoring capabilities without requiring a large internal security team.' },
  { term: 'MTD', fullName: 'Maximum Tolerable Downtime', definition: 'The longest period of time a business process can be disrupted before the disruption threatens the organization\'s survival or causes unacceptable harm. MTD defines the outer boundary for BCP and DR planning and directly influences RTO requirements.' },
  { term: 'MTO', fullName: 'Maximum Tolerable Outage', definition: 'The maximum length of time a business function can be unavailable before the impact becomes critical to the organization\'s survival. MTO is used interchangeably with MTD and helps prioritize which systems must be restored first during a disaster recovery event.' },
  { term: 'NAC', fullName: 'Network Access Control', definition: 'A security approach that enforces policy compliance before allowing devices to connect to a network, checking for proper authentication, patch levels, and security software. NAC prevents non-compliant or unauthorized devices from accessing network resources and can quarantine devices that fail health checks.' },
  { term: 'NAT', fullName: 'Network Address Translation', definition: 'A method of remapping one IP address space into another by modifying IP address information in packet headers as they transit a router, conserving public IP addresses. While NAT provides a degree of obscurity for internal network structure, it should not be relied upon as a primary security control.' },
  { term: 'NTLM', fullName: 'NT LAN Manager', definition: 'A Microsoft authentication protocol suite that uses challenge-response hashing to authenticate users. NTLM is vulnerable to Pass-the-Hash attacks (where captured NTLM hashes are reused without cracking), relay attacks, and offline dictionary attacks. Kerberos is preferred in Active Directory environments; NTLM should be disabled where possible.' },
  { term: 'NIST', fullName: 'National Institute of Standards and Technology', definition: 'A US federal agency that develops and promotes technology, measurement, and standards, including widely adopted cybersecurity frameworks and guidelines. NIST publications like SP 800-53 and the NIST Cybersecurity Framework provide authoritative guidance used across government and private sectors.' },
  { term: 'NIST CSF', fullName: 'NIST Cybersecurity Framework', definition: 'A voluntary framework developed by NIST that provides a common language and systematic methodology for managing cybersecurity risk across five core functions: Identify, Protect, Detect, Respond, and Recover. The NIST CSF helps organizations of all sizes align their security activities with business objectives and risk tolerance.' },
  { term: 'NGFW', fullName: 'Next-Generation Firewall', definition: 'An advanced firewall that goes beyond traditional port and protocol inspection to include application-layer filtering, intrusion prevention, SSL inspection, and user identity tracking. NGFWs provide deeper visibility and more granular control over network traffic than traditional stateful firewalls.' },
  { term: 'NTP', fullName: 'Network Time Protocol', definition: 'A networking protocol for clock synchronization between computer systems over packet-switched, variable-latency data networks. Accurate time synchronization is critical for security as it ensures log timestamps are consistent for forensic analysis and prevents time-based attacks on authentication systems.' },
  { term: 'NVD', fullName: 'National Vulnerability Database', definition: 'The US government repository of standards-based vulnerability management data using the CVSS scoring system, maintained by NIST. The NVD enriches CVE data with CVSS scores, weakness enumeration, and configuration information to help organizations assess and prioritize vulnerability remediation.' },
  { term: 'OAuth', fullName: 'Open Authorization', definition: 'An open standard for access delegation that allows third-party applications to access user resources on a service without exposing the user\'s credentials. OAuth is widely used for federated login and API authorization but must be carefully implemented to prevent token theft and scope escalation attacks.' },
  { term: 'OCSP', fullName: 'Online Certificate Status Protocol', definition: 'An internet protocol used to obtain the revocation status of an X.509 digital certificate in real time, providing a more efficient alternative to CRL checking. OCSP stapling improves performance by allowing the web server to provide a cached, CA-signed OCSP response to clients.' },
  { term: 'OIDC', fullName: 'OpenID Connect', definition: 'An identity layer built on top of OAuth 2.0 that allows client applications to verify the identity of end-users and obtain basic profile information. OIDC enables single sign-on across multiple applications and is widely used for federated identity in modern web and mobile applications.' },
  { term: 'OS', fullName: 'Operating System', definition: 'Software that manages computer hardware and software resources and provides common services for computer programs. OS hardening, including removing unnecessary services, applying patches, and configuring secure settings, is a fundamental security control for reducing the attack surface.' },
  { term: 'OSINT', fullName: 'Open Source Intelligence', definition: 'The collection and analysis of information gathered from publicly available sources such as social media, websites, public records, and news. Attackers use OSINT to gather information for targeted attacks, while defenders use it for threat intelligence and to understand what information about their organization is publicly available.' },
  { term: 'OTP', fullName: 'One-Time Password', definition: 'A password that is valid for only one login session or transaction, generated using time-based (TOTP) or counter-based (HOTP) algorithms. OTPs are used as a second authentication factor to prevent replay attacks, since a captured OTP cannot be reused by an attacker.' },
  { term: 'OWASP', fullName: 'Open Web Application Security Project', definition: 'A nonprofit foundation that works to improve software security by providing free, community-produced resources including the OWASP Top 10 list of critical web application security risks. OWASP guidance is widely referenced in security assessments, development standards, and compliance frameworks.' },
  { term: 'PaaS', fullName: 'Platform as a Service', definition: 'A cloud computing model that provides a platform allowing customers to develop, run, and manage applications without dealing with the underlying infrastructure. In PaaS, the provider secures the infrastructure and platform, while the customer is responsible for securing their applications and data.' },
  { term: 'PAM', fullName: 'Privileged Access Management', definition: 'A set of technologies and processes designed to secure, control, monitor, and audit privileged access to critical assets. PAM solutions manage privileged credentials, record privileged sessions, and enforce just-in-time access to reduce the risk of insider threats and lateral movement by external attackers.' },
  { term: 'PAT', fullName: 'Port Address Translation', definition: 'A type of NAT that maps multiple private IP addresses to a single public IP address by differentiating connections using port numbers, also known as NAT overload. PAT allows many devices to share a single public IP address while maintaining separate communication sessions.' },
  { term: 'PCI-DSS', fullName: 'Payment Card Industry Data Security Standard', definition: 'A set of security standards designed to ensure that all companies that accept, process, store, or transmit credit card information maintain a secure environment. PCI-DSS compliance is required for merchants and service providers handling cardholder data, with non-compliance resulting in fines and loss of card processing privileges.' },
  { term: 'PEAP', fullName: 'Protected Extensible Authentication Protocol', definition: 'An EAP method that creates an encrypted and authenticated TLS tunnel within which other EAP methods can be used for inner authentication. PEAP is widely used in enterprise wireless networks because it only requires a server-side certificate while still providing strong protection for user credentials.' },
  { term: 'PGP', fullName: 'Pretty Good Privacy', definition: 'An encryption program that provides cryptographic privacy and authentication for data communication, using a combination of symmetric and asymmetric encryption. PGP uses a web of trust model for key validation rather than a PKI hierarchy and is commonly used for encrypting email and files.' },
  { term: 'PHI', fullName: 'Protected Health Information', definition: 'Any individually identifiable health information that is created, received, maintained, or transmitted by covered entities under HIPAA. PHI includes medical records, billing information, and any other health data that can be linked to a specific individual, requiring strict security and privacy protections.' },
  { term: 'PII', fullName: 'Personally Identifiable Information', definition: 'Any information that can be used to identify, contact, or locate a specific individual, either alone or in combination with other information. PII is subject to privacy regulations such as GDPR, HIPAA, and CCPA, and its protection is a core responsibility for any organization that collects it.' },
  { term: 'PKI', fullName: 'Public Key Infrastructure', definition: 'A framework of roles, policies, hardware, software, and procedures needed to create, manage, distribute, use, store, and revoke digital certificates and manage public-key encryption. PKI enables secure electronic transfer of information and underpins trust in digital communications through the use of certificate authorities.' },
  { term: 'PtH', fullName: 'Pass the Hash', definition: 'An attack technique where an attacker captures a hashed user credential and uses it directly to authenticate to remote systems without needing to crack the actual password. PtH attacks exploit the NTLM authentication protocol and are mitigated through credential guard, network segmentation, and privileged access workstations.' },
  { term: 'RADIUS', fullName: 'Remote Authentication Dial-In User Service', definition: 'A networking protocol that provides centralized authentication, authorization, and accounting management for users connecting to a network service. RADIUS is widely used with 802.1X for wired and wireless network access control and supports various EAP methods for authentication.' },
  { term: 'RBAC', fullName: 'Role-Based Access Control', definition: 'An access control model that grants permissions to users based on their organizational roles rather than individual identity, following the principle of least privilege. RBAC simplifies access administration, reduces the risk of privilege creep, and makes it easier to audit who has access to what resources.' },
  { term: 'RCE', fullName: 'Remote Code Execution', definition: 'A class of security vulnerability that allows an attacker to execute arbitrary code on a target system over a network. RCE vulnerabilities are among the most severe security flaws as they can lead to complete system compromise and are often the goal of exploitation chains.' },
  { term: 'RFI', fullName: 'Remote File Inclusion', definition: 'A web application vulnerability that allows an attacker to include a remote file, usually through user-supplied input, causing the server to execute malicious code hosted on the attacker\'s server. RFI is prevented by disabling remote file inclusion in PHP configurations and validating all user-supplied file paths.' },
  { term: 'RPO', fullName: 'Recovery Point Objective', definition: 'The maximum acceptable amount of data loss measured in time, representing how far back in time recovery must go to restore normal operations after a disruption. RPO directly influences backup frequency requirements; a lower RPO requires more frequent backups and data replication.' },
  { term: 'RSA', fullName: 'Rivest-Shamir-Adleman', definition: 'A widely used asymmetric encryption algorithm based on the computational difficulty of factoring large prime numbers, supporting key sizes of 1024 to 4096 bits. RSA is used for key exchange, digital signatures, and certificate-based authentication, though key sizes of at least 2048 bits are recommended for current security.' },
  { term: 'RTO', fullName: 'Recovery Time Objective', definition: 'The maximum acceptable length of time that a system, application, or business process can be offline after a disruption before the impact becomes unacceptable. RTO drives decisions about redundancy, failover capabilities, and the resources invested in disaster recovery planning.' },
  { term: 'SaaS', fullName: 'Software as a Service', definition: 'A cloud computing model where software applications are delivered over the internet on a subscription basis, with the provider managing all underlying infrastructure, middleware, and application software. In SaaS, the customer is primarily responsible for securing user access, data they upload, and configuring application security settings.' },
  { term: 'SAML', fullName: 'Security Assertion Markup Language', definition: 'An XML-based open standard for exchanging authentication and authorization data between parties, particularly between an identity provider and a service provider. SAML enables single sign-on across different domains and is widely used in enterprise environments for federated identity management.' },
  { term: 'SASE', fullName: 'Secure Access Service Edge', definition: 'A cloud-delivered security framework that combines network security functions such as CASB, SWG, ZTNA, and FWaaS with WAN capabilities (SD-WAN) into a single cloud service. SASE provides secure access for remote users and branch offices without backhauling traffic through a corporate data center.' },
  { term: 'SCAP', fullName: 'Security Content Automation Protocol', definition: 'A method for using specific standards to enable automated vulnerability management, measurement, and policy compliance evaluation. SCAP uses standards like OVAL, XCCDF, and CVE to automate security configuration checking and vulnerability assessment.' },
  { term: 'SD-WAN', fullName: 'Software-Defined Wide Area Network', definition: 'A virtual WAN architecture that allows enterprises to leverage any combination of transport services to securely connect users to applications, using a software-defined approach to network management. SD-WAN security must include encryption of traffic across untrusted links and centralized policy management.' },
  { term: 'SDLC', fullName: 'Software Development Life Cycle', definition: 'A structured process for planning, creating, testing, and deploying information systems, encompassing phases from requirements gathering to maintenance. Integrating security into each phase of the SDLC (DevSecOps) is essential to identify and remediate vulnerabilities before they reach production.' },
  { term: 'SHA', fullName: 'Secure Hash Algorithm', definition: 'A family of cryptographic hash functions published by NIST, including SHA-1 (160-bit), SHA-256, and SHA-512. SHA-1 is deprecated due to collision vulnerabilities, while SHA-256 and SHA-512 (SHA-2 family) remain secure and are widely used for digital signatures, certificates, and data integrity verification.' },
  { term: 'SIEM', fullName: 'Security Information and Event Management', definition: 'A platform that aggregates and correlates security event data from across an organization\'s IT infrastructure in real time, enabling threat detection, incident response, and compliance reporting. SIEM solutions use rules and analytics to identify patterns indicating security incidents among vast amounts of log data.' },
  { term: 'SLA', fullName: 'Service Level Agreement', definition: 'A contract between a service provider and customer that defines the expected level of service, including availability, performance, and security requirements. SLAs should include security provisions such as incident response timelines, breach notification requirements, and audit rights.' },
  { term: 'SLE', fullName: 'Single Loss Expectancy', definition: 'A quantitative risk metric that represents the expected monetary loss from a single occurrence of a specific threat against a specific asset. SLE is calculated by multiplying the asset value by the exposure factor and is used as an input to calculate ALE.' },
  { term: 'S/MIME', fullName: 'Secure/Multipurpose Internet Mail Extensions', definition: 'A standard for public key encryption and signing of MIME data, widely used to provide end-to-end encryption and digital signing for email messages. S/MIME requires each recipient to have a digital certificate, providing stronger security than transport-level email encryption alone.' },
  { term: 'SMTP', fullName: 'Simple Mail Transfer Protocol', definition: 'The standard protocol for sending email messages between servers over the internet. SMTP can be secured using STARTTLS or SMTPS to encrypt email in transit, and SPF, DKIM, and DMARC records help authenticate email senders and prevent spoofing.' },
  { term: 'SNMP', fullName: 'Simple Network Management Protocol', definition: 'A protocol used for collecting and organizing information about managed devices on IP networks and modifying that information to change device behavior. SNMPv1 and SNMPv2 transmit community strings in cleartext, making SNMPv3 with authentication and encryption the required version for secure environments.' },
  { term: 'SOC', fullName: 'Security Operations Center', definition: 'A centralized facility staffed by security analysts who monitor, detect, analyze, and respond to cybersecurity incidents in real time using a combination of technology and human expertise. A SOC provides continuous visibility into an organization\'s security posture and coordinates incident response activities.' },
  { term: 'SOC 2', fullName: 'System and Organization Controls 2', definition: 'An auditing standard developed by the AICPA that evaluates a service organization\'s controls relevant to security, availability, processing integrity, confidentiality, and privacy. SOC 2 reports are commonly required by enterprise customers to assess the security posture of their cloud and SaaS vendors.' },
  { term: 'SOAR', fullName: 'Security Orchestration, Automation, and Response', definition: 'A solution that combines security orchestration and automation with incident response to help security teams manage and respond to security alerts more efficiently. SOAR platforms use playbooks to automate repetitive tasks, reducing response times and allowing analysts to focus on complex threats.' },
  { term: 'SPF', fullName: 'Sender Policy Framework', definition: 'An email authentication method that specifies which mail servers are authorized to send email on behalf of a domain by publishing a DNS record. SPF helps prevent email spoofing by allowing receiving servers to verify that incoming email from a domain comes from an authorized sender.' },
  { term: 'SQL Injection', fullName: 'Structured Query Language Injection', definition: 'An attack technique where malicious SQL code is inserted into an entry field for execution by the backend database, allowing attackers to manipulate, extract, or destroy database contents. SQL injection is prevented through parameterized queries, prepared statements, input validation, and least-privilege database accounts.' },
  { term: 'SSH', fullName: 'Secure Shell', definition: 'A cryptographic network protocol for operating network services securely over an unsecured network, providing encrypted remote access to systems. SSH uses asymmetric cryptography for authentication and symmetric encryption for session data, and should replace insecure protocols like Telnet and rlogin.' },
  { term: 'SSL', fullName: 'Secure Sockets Layer', definition: 'A deprecated cryptographic protocol that provided communications security over a computer network, superseded by TLS. SSL versions 2.0 and 3.0 are known to have critical vulnerabilities (POODLE, DROWN) and must be disabled; TLS 1.2 or 1.3 should be used instead.' },
  { term: 'SSO', fullName: 'Single Sign-On', definition: 'An authentication scheme that allows users to log in once with a single set of credentials and gain access to multiple related but independent systems. SSO improves user experience and reduces password fatigue but creates a high-value target, as compromising SSO credentials can grant access to all connected applications.' },
  { term: 'SSRF', fullName: 'Server-Side Request Forgery', definition: 'A web vulnerability that allows an attacker to induce the server to make HTTP requests to an arbitrary domain chosen by the attacker, often used to access internal services and cloud metadata APIs. SSRF can lead to data exfiltration, internal port scanning, and compromise of cloud credentials.' },
  { term: 'STIX', fullName: 'Structured Threat Information eXpression', definition: 'A standardized language and serialization format for cyber threat intelligence that enables the consistent sharing of threat information between organizations and tools. STIX is used with the TAXII protocol to automate the exchange of threat intelligence indicators.' },
  { term: 'SWG', fullName: 'Secure Web Gateway', definition: 'A security solution that filters internet traffic and enforces company policy compliance for outbound web requests, providing URL filtering, malware detection, and data loss prevention. SWGs protect users from web-based threats regardless of their location, making them a key component of SASE architectures.' },
  { term: 'TACACS+', fullName: 'Terminal Access Controller Access Control System Plus', definition: 'A Cisco-proprietary AAA protocol that provides separate authentication, authorization, and accounting processes and encrypts the entire packet body unlike RADIUS. TACACS+ is commonly used for device administration access control in network infrastructure, providing more granular command authorization than RADIUS.' },
  { term: 'TAXII', fullName: 'Trusted Automated eXchange of Intelligence Information', definition: 'An application protocol for exchanging CTI over HTTPS that defines a RESTful API with a set of interoperability requirements. TAXII works in conjunction with STIX to enable automated sharing of threat intelligence between organizations.' },
  { term: 'TLS', fullName: 'Transport Layer Security', definition: 'A cryptographic protocol that provides communications security over a computer network by encrypting data in transit and authenticating communicating parties. TLS 1.3 is the current recommended version, offering improved security and performance, while TLS 1.0 and 1.1 are deprecated and should be disabled.' },
  { term: 'TOTP', fullName: 'Time-Based One-Time Password', definition: 'A temporary passcode generated by an algorithm that uses the current time as one of its inputs, producing a unique code that changes every 30 seconds. TOTP is a common MFA mechanism used by authenticator apps like Google Authenticator and is more resistant to phishing than SMS-based codes.' },
  { term: 'TPM', fullName: 'Trusted Platform Module', definition: 'A secure cryptoprocessor chip on a computer\'s motherboard that provides hardware-based security functions including secure key generation, storage, and attestation. TPM is used for full disk encryption, measured boot, and storing cryptographic keys in a tamper-resistant hardware component.' },
  { term: 'TTX', fullName: 'Tabletop Exercise', definition: 'A discussion-based exercise where team members walk through a simulated emergency or security incident scenario in an informal, low-stress environment to evaluate response plans. TTXs identify gaps in incident response procedures and improve coordination without requiring the disruption of live exercises.' },
  { term: 'TTP', fullName: 'Tactics, Techniques, and Procedures', definition: 'The behavior patterns, methods, and operational procedures used by threat actors to accomplish their objectives, as documented in frameworks like MITRE ATT&CK. Understanding adversary TTPs enables defenders to focus on detecting attacker behavior rather than just specific malware artifacts.' },
  { term: 'UBA', fullName: 'User Behavior Analytics', definition: 'A cybersecurity process that uses machine learning and statistical analysis to detect anomalies in the behavior patterns of users within a network. UBA identifies insider threats, compromised accounts, and targeted attacks by establishing behavioral baselines and flagging deviations.' },
  { term: 'UEM', fullName: 'Unified Endpoint Management', definition: 'An approach to managing all endpoint devices including desktops, laptops, smartphones, tablets, and IoT devices through a single platform. UEM evolved from MDM and EMM to provide comprehensive visibility and control across all endpoint types and operating systems.' },
  { term: 'URL', fullName: 'Uniform Resource Locator', definition: 'The address used to access resources on the internet, specifying the protocol, domain, path, and optional parameters. URL manipulation attacks including path traversal, parameter tampering, and open redirects are common web application vulnerabilities that require input validation and access controls.' },
  { term: 'UTM', fullName: 'Unified Threat Management', definition: 'A comprehensive security solution that integrates multiple security features including firewall, IDS/IPS, antivirus, anti-spam, VPN, and content filtering into a single appliance. UTM simplifies security management but can become a single point of failure and may introduce performance bottlenecks.' },
  { term: 'VLAN', fullName: 'Virtual Local Area Network', definition: 'A logical subdivision of a physical network that groups devices together regardless of their physical location, providing network segmentation at the data link layer. VLANs reduce the broadcast domain, limit lateral movement opportunities for attackers, and enforce network segmentation without additional hardware.' },
  { term: 'VM', fullName: 'Virtual Machine', definition: 'A software emulation of a physical computer that runs an operating system and applications as if it were a physical machine, sharing the underlying hardware with other VMs. VM escape vulnerabilities allow attackers to break out of a virtualized environment and access the hypervisor or other VMs.' },
  { term: 'VPN', fullName: 'Virtual Private Network', definition: 'A secure, encrypted connection established over a public network that allows remote users or sites to access private network resources as if they were directly connected. VPNs are used to protect data in transit and provide secure remote access, using protocols like IPSec, SSL/TLS, or WireGuard.' },
  { term: 'WAF', fullName: 'Web Application Firewall', definition: 'A security solution that monitors, filters, and blocks HTTP/HTTPS traffic to and from a web application based on rules that identify known attack patterns. WAFs protect against OWASP Top 10 threats like SQL injection, XSS, and CSRF, and can be deployed as hardware, software, or cloud services.' },
  { term: 'WEP', fullName: 'Wired Equivalent Privacy', definition: 'A deprecated wireless security protocol introduced in 1997 that uses RC4 stream cipher with static keys and weak initialization vectors. WEP is fundamentally broken and can be cracked in minutes using freely available tools; it must never be used in any environment and should be replaced with WPA3.' },
  { term: 'WPA2', fullName: 'Wi-Fi Protected Access 2', definition: 'A wireless security protocol using AES-CCMP encryption and IEEE 802.11i. WPA2-Personal uses a Pre-Shared Key (PSK) vulnerable to offline dictionary attacks against the 4-way handshake; WPA2-Enterprise uses 802.1X/EAP for stronger per-user authentication. WPA2 remains widely deployed but is superseded by WPA3.' },
  { term: 'WPA3', fullName: 'Wi-Fi Protected Access 3', definition: 'The latest Wi-Fi security standard that provides stronger encryption using SAE (Simultaneous Authentication of Equals) instead of the PSK handshake, offering protection against offline dictionary attacks and forward secrecy. WPA3 also includes Wi-Fi Easy Connect for IoT devices and Enhanced Open for public hotspot encryption.' },
  { term: 'XDR', fullName: 'Extended Detection and Response', definition: 'A security solution that unifies data collection and response capabilities across endpoints, networks, cloud workloads, and email to provide a holistic view of threats. XDR correlates signals across multiple security tools to reduce alert fatigue and improve detection of sophisticated, multi-stage attacks.' },
  { term: 'XSRF', fullName: 'Cross-Site Request Forgery', definition: 'An attack (also known as CSRF) that tricks an authenticated user into unknowingly submitting a malicious request to a web application in which they are currently authenticated. XSRF exploits the trust a website has in a user\'s browser and is mitigated by anti-CSRF tokens, SameSite cookies, and re-authentication for sensitive actions.' },
  { term: 'XTACACS', fullName: 'Extended Terminal Access Controller Access Control System', definition: 'A Cisco proprietary extension of the original TACACS protocol that separates authentication and authorization functions. XTACACS was superseded by TACACS+ (which encrypts the full packet) and is now considered obsolete. It appears on CompTIA exams as a historical reference in the evolution of AAA protocols.' },
  { term: 'XML', fullName: 'Extensible Markup Language', definition: 'A markup language that defines rules for encoding documents in a format that is both human-readable and machine-readable, widely used for data interchange. XML parsing vulnerabilities including XXE (XML External Entity) attacks can lead to data exfiltration, SSRF, and denial of service.' },
  { term: 'XSS', fullName: 'Cross-Site Scripting', definition: 'A web vulnerability that allows attackers to inject malicious scripts into web pages viewed by other users, exploiting the trust that a user has in a particular website. XSS can be used to steal session cookies, redirect users to malicious sites, and perform actions on behalf of the victim; it is prevented through output encoding and Content Security Policy.' },
  { term: 'XXE', fullName: 'XML External Entity', definition: 'A web security vulnerability that allows an attacker to interfere with an application\'s processing of XML data by referencing an external entity within the XML. XXE can lead to server-side request forgery, file disclosure, and denial of service attacks, and is mitigated by disabling external entity processing in XML parsers.' },
  { term: 'ZTNA', fullName: 'Zero Trust Network Access', definition: 'A security model that assumes no user or device should be inherently trusted and requires continuous verification of identity and device health before granting access to applications and data. ZTNA replaces traditional VPN-based remote access with more granular, identity-centric controls aligned with the Zero Trust architecture.' },
  { term: 'ZTP', fullName: 'Zero Touch Provisioning', definition: 'A method of setting up devices that automatically configures them when connected to the network, eliminating the need for manual intervention. ZTP security concerns include the risk of provisioning malicious configurations if the provisioning server or process is compromised.' },
  { term: 'ACL', fullName: 'Access Control List', definition: 'A set of rules that defines which users or system processes are granted or denied access to specific network resources or objects. ACLs are implemented on routers, firewalls, and operating systems to enforce traffic filtering and object-level permissions.' },
  { term: 'ARP Poisoning', fullName: 'Address Resolution Protocol Poisoning', definition: 'An attack where false ARP messages are sent over a local network to link the attacker\'s MAC address with the IP address of a legitimate host. ARP poisoning enables man-in-the-middle attacks, traffic interception, and denial of service within the local network segment.' },
  { term: 'AS', fullName: 'Authentication Server', definition: 'A server that verifies the identity of users attempting to access a network or system, typically used in Kerberos and RADIUS deployments. The AS is a critical component of AAA infrastructure and must be highly secured as its compromise can lead to complete authentication bypass.' },
  { term: 'BIA', fullName: 'Business Impact Analysis', definition: 'A systematic process to determine and evaluate the potential effects of an interruption to critical business operations as a result of a disaster or incident. BIA identifies the most critical systems and processes, defines recovery priorities, and informs RTO and RPO objectives.' },
  { term: 'BYOD Policy', fullName: 'Bring Your Own Device Policy', definition: 'A formal organizational policy that defines acceptable use, security requirements, and management controls for personal devices used to access corporate resources. An effective BYOD policy addresses MDM enrollment, data separation, acceptable use, and procedures for device loss or employee departure.' },
  { term: 'C2', fullName: 'Command and Control', definition: 'The infrastructure used by attackers to communicate with and control compromised systems (bots or implants) in a target network. C2 detection and disruption is a key defensive goal, as cutting off communication between malware and its operators can stop an active attack.' },
  { term: 'CHROOT', fullName: 'Change Root', definition: 'A Unix operation that changes the apparent root directory for the current running process and its children, creating a sandboxed environment. Chroot jails limit the blast radius of a compromised process by restricting its access to the filesystem.' },
  { term: 'CISO', fullName: 'Chief Information Security Officer', definition: 'The senior executive responsible for developing and implementing an information security program to protect organizational assets and ensure regulatory compliance. The CISO bridges technical security capabilities with business strategy and risk management at the executive level.' },
  { term: 'COA', fullName: 'Course of Action', definition: 'In cybersecurity, a set of actions or steps that can be taken to respond to a specific threat or attacker technique. COAs are used in threat intelligence frameworks to describe defensive mitigations against known TTPs.' },
  { term: 'COPE', fullName: 'Corporate-Owned, Personally Enabled', definition: 'A mobile device strategy where the organization provides employees with corporate-owned devices that employees are permitted to use for personal purposes within policy limits. COPE gives organizations greater control over security than BYOD while improving employee satisfaction compared to purely corporate-restricted devices.' },
  { term: 'CPU', fullName: 'Central Processing Unit', definition: 'The primary component of a computer that executes instructions and processes data. CPU-level vulnerabilities like Spectre and Meltdown can bypass hardware isolation boundaries and expose sensitive data from other processes, representing a significant hardware security concern.' },
  { term: 'CTF', fullName: 'Capture The Flag', definition: 'A type of cybersecurity competition where participants solve security challenges to find hidden flags, covering topics like web exploitation, cryptography, reverse engineering, and forensics. CTF competitions are used for security training and to develop practical offensive and defensive security skills.' },
  { term: 'CUI', fullName: 'Controlled Unclassified Information', definition: 'Government-created or government-owned information that requires safeguarding or dissemination controls consistent with applicable laws, regulations, and policies. Organizations handling CUI for the US government must implement NIST SP 800-171 controls and may require CMMC certification.' },
  { term: 'DAM', fullName: 'Database Activity Monitoring', definition: 'A security technology that monitors and analyzes database activity to detect unauthorized access, data exfiltration, and policy violations in real time. DAM solutions provide visibility into database operations without relying on native database audit logs, which can be disabled or modified by privileged users.' },
  { term: 'DAST', fullName: 'Dynamic Application Security Testing', definition: 'A black-box testing method that examines a running application from the outside to identify vulnerabilities such as XSS, SQL injection, and authentication flaws. DAST tools simulate attacker behavior against live applications and complement SAST by finding vulnerabilities that only manifest at runtime.' },
  { term: 'DKIM', fullName: 'DomainKeys Identified Mail', definition: 'An email authentication method that uses a digital signature to verify that an email message was authorized by the owner of the sending domain. DKIM signatures are added to email headers and verified using a public key published in DNS, helping prevent email spoofing and message tampering.' },
  { term: 'DMARC', fullName: 'Domain-based Message Authentication, Reporting, and Conformance', definition: 'An email authentication policy and reporting protocol that builds on SPF and DKIM to specify how receiving mail servers should handle messages that fail authentication checks. DMARC provides domain owners with visibility into email authentication failures and enables enforcement of reject or quarantine policies.' },
  { term: 'DNS Sinkhole', fullName: 'Domain Name System Sinkhole', definition: 'A DNS server that returns false responses for known malicious domain names, redirecting malware communication attempts to a controlled IP address. DNS sinkholes are used to detect infected hosts, disrupt botnet communications, and gather intelligence about malware behavior.' },
  { term: 'DoH', fullName: 'DNS over HTTPS', definition: 'A protocol that performs DNS resolution over HTTPS instead of the traditional plaintext UDP protocol, encrypting DNS queries to prevent eavesdropping and manipulation. DoH improves privacy but can bypass enterprise DNS monitoring and filtering controls, creating a security management challenge.' },
  { term: 'DoT', fullName: 'DNS over TLS', definition: 'A protocol that encrypts DNS queries using TLS to prevent eavesdropping, manipulation, and spoofing of DNS traffic. Unlike DoH, DoT uses a dedicated port (853), making it easier for network administrators to monitor and control DNS traffic.' },
  { term: 'DPO', fullName: 'Data Protection Officer', definition: 'A leadership role required by GDPR for organizations that process personal data at scale, responsible for ensuring compliance with data protection regulations. The DPO advises on data protection impact assessments, monitors compliance, and serves as the contact point for supervisory authorities.' },
  { term: 'DSA', fullName: 'Digital Signature Algorithm', definition: 'A federal standard for digital signatures based on the mathematical concept of modular exponentiation, used to verify the authenticity and integrity of digital messages. DSA is used in conjunction with SHA to create a complete digital signature standard (DSS).' },
  { term: 'DKIM', fullName: 'DomainKeys Identified Mail', definition: 'An email authentication method that adds a digital signature to outgoing messages, allowing receiving servers to verify the message was sent and authorized by the owner of the sending domain. DKIM is a critical component of email security alongside SPF and DMARC.' },
  { term: 'EAP-TTLS', fullName: 'Extensible Authentication Protocol - Tunneled Transport Layer Security', definition: 'An EAP method that creates a TLS tunnel for secure transmission of legacy authentication credentials, requiring only a server-side certificate. EAP-TTLS supports a wide range of inner authentication methods including PAP, CHAP, and MS-CHAPv2.' },
  { term: 'FIDO2', fullName: 'Fast Identity Online 2', definition: 'A set of open authentication standards that enable passwordless authentication using hardware security keys, biometrics, or platform authenticators. FIDO2 is resistant to phishing, credential stuffing, and man-in-the-middle attacks as authentication is bound to the origin website.' },
  { term: 'FTP', fullName: 'File Transfer Protocol', definition: 'A standard network protocol used for transferring files between a client and server over a TCP network. FTP transmits credentials and data in cleartext and should be replaced with SFTP (SSH File Transfer Protocol) or FTPS (FTP over SSL/TLS) in any environment handling sensitive data.' },
  { term: 'GRE', fullName: 'Generic Routing Encapsulation', definition: 'A tunneling protocol developed by Cisco that encapsulates a wide variety of network layer protocols inside virtual point-to-point links. GRE itself provides no encryption, so it is often combined with IPSec to create secure GRE over IPSec tunnels for VPN connectivity.' },
  { term: 'HA', fullName: 'High Availability', definition: 'A system design approach that uses redundancy, clustering, and failover mechanisms to minimize downtime and ensure systems remain accessible despite component failures. HA is measured as a percentage of uptime (e.g., 99.999% or "five nines" equals approximately 5 minutes of downtime per year).' },
  { term: 'HOTP', fullName: 'HMAC-based One-Time Password', definition: 'A one-time password algorithm that generates codes using a shared secret and a counter that increments with each use, defined in RFC 4226. Unlike TOTP, HOTP codes do not expire based on time and are valid until used, making them suitable for hardware tokens where time synchronization is impractical.' },
  { term: 'HIDS', fullName: 'Host-based Intrusion Detection System', definition: 'A security agent installed on individual hosts that monitors system activity, log files, and file integrity to detect suspicious behavior and policy violations. HIDS provides visibility into host-level threats that network-based IDS systems cannot see, such as insider threats and malware that avoids network-based detection.' },
  { term: 'IAB', fullName: 'Initial Access Broker', definition: 'A cybercriminal who specializes in gaining unauthorized access to organizations and selling that access to other threat actors such as ransomware groups. IABs represent a significant threat as they commoditize network access, enabling less sophisticated actors to launch sophisticated attacks.' },
  { term: 'IDPS', fullName: 'Intrusion Detection and Prevention System', definition: 'A security system that combines intrusion detection (passive monitoring and alerting) with intrusion prevention (active blocking) capabilities in a single solution. IDPS can operate in detection-only mode or inline prevention mode, using signature-based and anomaly-based detection methods.' },
  { term: 'ISMS', fullName: 'Information Security Management System', definition: 'A systematic framework of policies, processes, procedures, and controls for managing information security risks within an organization, as defined by ISO/IEC 27001. An ISMS follows a Plan-Do-Check-Act cycle of continuous improvement and can be certified through third-party audit.' },
  { term: 'ICS', fullName: 'Industrial Control System', definition: 'Information systems used to control industrial processes such as power generation, water treatment, and manufacturing, including SCADA and DCS systems. ICS security is critical infrastructure protection, as successful attacks can have physical consequences ranging from production disruption to environmental damage and loss of life.' },
  { term: 'IKEv2', fullName: 'Internet Key Exchange version 2', definition: 'The second version of the IKE protocol used in IPSec, providing improved security, reliability, and mobile device support through MOBIKE. IKEv2 is the recommended version for VPN implementations and is resistant to several attacks that affected IKEv1.' },
  { term: 'IMAP', fullName: 'Internet Message Access Protocol', definition: 'A protocol used for retrieving email messages from a mail server, allowing email to be managed directly on the server. IMAP should be secured using TLS (IMAPS on port 993) to prevent credential interception and should have access controlled through strong authentication.' },
  { term: 'IPFIX', fullName: 'IP Flow Information Export', definition: 'A standard protocol for collecting and exporting network flow information from routers and switches for network monitoring and security analysis. IPFIX data is used in security analytics to detect anomalous traffic patterns, DDoS attacks, and data exfiltration.' },
  { term: 'ISO 27001', fullName: 'International Organization for Standardization 27001', definition: 'An international standard that specifies requirements for establishing, implementing, maintaining, and continually improving an information security management system (ISMS). ISO 27001 certification demonstrates that an organization has implemented comprehensive controls to manage information security risks.' },
  { term: 'ISP', fullName: 'Internet Service Provider', definition: 'A company that provides internet access and related services to individuals and organizations. ISPs play a role in cybersecurity by providing upstream DDoS mitigation, BGP filtering to prevent route hijacking, and abuse response for attacks originating from their networks.' },
  { term: 'KPI', fullName: 'Key Performance Indicator', definition: 'A measurable value that demonstrates how effectively an organization is achieving its key security objectives. Security KPIs such as mean time to detect (MTTD) and mean time to respond (MTTR) are used to measure SOC effectiveness and track security program improvement.' },
  { term: 'KRI', fullName: 'Key Risk Indicator', definition: 'A metric used to indicate the level of risk associated with a particular activity or process, providing early warning of increasing risk exposure. KRIs help organizations proactively manage risks before they materialize into security incidents.' },
  { term: 'L2TP', fullName: 'Layer 2 Tunneling Protocol', definition: 'A tunneling protocol used to create VPN connections that does not provide encryption on its own and is typically paired with IPSec for security. L2TP/IPSec is a common VPN configuration on legacy systems, though modern deployments prefer IKEv2/IPSec or WireGuard.' },
  { term: 'LFI', fullName: 'Local File Inclusion', definition: 'A web application vulnerability that allows an attacker to include files from the server\'s local filesystem in the response, potentially exposing sensitive configuration files or allowing code execution. LFI is prevented through input validation, avoiding user-controlled paths, and implementing proper file access controls.' },
  { term: 'LOE', fullName: 'Level of Effort', definition: 'An estimate of the total resources, time, and work required to complete a project or remediation task. In security contexts, LOE is used to prioritize remediation work — comparing the LOE required to fix a vulnerability against the risk reduction it provides helps organizations allocate limited resources effectively.' },
  { term: 'LEAP', fullName: 'Lightweight Extensible Authentication Protocol', definition: 'A Cisco-proprietary EAP method for wireless authentication that is now deprecated due to known cryptographic weaknesses. LEAP is vulnerable to dictionary attacks against the MS-CHAPv2 authentication it uses and should be replaced with EAP-TLS or PEAP.' },
  { term: 'MITM', fullName: 'Man-in-the-Middle', definition: 'An attack where the attacker secretly relays and potentially alters communications between two parties who believe they are communicating directly with each other. MITM attacks can capture credentials, inject malicious content, and intercept sensitive data; they are mitigated through certificate pinning, mutual TLS, and HSTS.' },
  { term: 'MOU', fullName: 'Memorandum of Understanding', definition: 'A formal but typically non-binding agreement between two or more parties that outlines the terms of a cooperative relationship or data sharing arrangement. In cybersecurity, MOUs often govern information sharing between organizations regarding threats, incidents, and vulnerabilities.' },
  { term: 'MSSP', fullName: 'Managed Security Service Provider', definition: 'An organization that provides outsourced monitoring and management of security systems and devices, offering capabilities that many organizations cannot maintain internally. MSSPs should be vetted as a supply chain risk since they typically have deep access to client security infrastructure.' },
  { term: 'NAT Traversal', fullName: 'Network Address Translation Traversal', definition: 'A set of techniques that allow network traffic to pass through NAT devices, commonly needed for VoIP, peer-to-peer, and VPN protocols that embed IP addresses in their payloads. NAT traversal is implemented in protocols like STUN, TURN, and ICE.' },
  { term: 'NIDS', fullName: 'Network Intrusion Detection System', definition: 'A security device or software that monitors network traffic for suspicious activity and known threat signatures, generating alerts for security analysts to investigate. NIDS provides network-wide visibility into attack patterns but cannot inspect encrypted traffic without additional decryption capabilities.' },
  { term: 'NIPS', fullName: 'Network Intrusion Prevention System', definition: 'An inline security solution that monitors network traffic and automatically blocks detected threats based on signatures and behavioral analysis. NIPS sits in the traffic path and can drop malicious packets before they reach their destination.' },
  { term: 'OT', fullName: 'Operational Technology', definition: 'Hardware and software that monitors and controls physical devices, processes, and infrastructure in industrial environments. OT security differs from IT security in that availability is often prioritized over confidentiality, and patching cycles are much longer due to operational constraints.' },
  { term: 'P2P', fullName: 'Peer-to-Peer', definition: 'A distributed computing architecture where each participant (peer) can act as both a client and a server, sharing resources directly without a central server. P2P networks are used by some malware for C2 communications as they are more resilient to takedown than centralized infrastructure.' },
  { term: 'PBKDF2', fullName: 'Password-Based Key Derivation Function 2', definition: 'A key stretching algorithm that applies a pseudorandom function (such as HMAC-SHA256) to a password along with a salt, repeated thousands or millions of times to make brute-force attacks computationally expensive. PBKDF2 is used for password storage and deriving encryption keys from passwords, and is recommended by NIST.' },
  { term: 'PIV', fullName: 'Personal Identity Verification', definition: 'A US federal government smart card standard (FIPS 201) used for authenticating the identity of federal employees and contractors to access government facilities and information systems. PIV cards contain certificates, private keys, and biometric data, enabling PKI-based authentication and digital signing.' },
  { term: 'PAP', fullName: 'Password Authentication Protocol', definition: 'A simple authentication protocol that transmits usernames and passwords in cleartext over a network connection. PAP is considered insecure for any network where traffic could be intercepted and should be replaced with CHAP, EAP, or other secure authentication methods.' },
  { term: 'PASTA', fullName: 'Process for Attack Simulation and Threat Analysis', definition: 'A risk-centric threat modeling methodology that simulates attacker goals and aligns business objectives with technical requirements and threat analysis. PASTA produces a threat model that helps prioritize security investments based on probable attack scenarios.' },
  { term: 'PBX', fullName: 'Private Branch Exchange', definition: 'A telephone switching system used within an enterprise that allows internal communication and provides connections to the public switched telephone network. IP PBX systems face VoIP-specific security threats including eavesdropping, toll fraud, and denial of service attacks.' },
  { term: 'PCAP', fullName: 'Packet Capture', definition: 'The process of intercepting and recording data packets traveling over a network for analysis, troubleshooting, or forensic investigation. PCAP files contain raw network traffic and are used by security analysts to investigate incidents, analyze malware communication, and conduct network forensics.' },
  { term: 'PEM', fullName: 'Privacy Enhanced Mail', definition: 'A Base64-encoded format for storing and transmitting cryptographic objects such as certificates, keys, and certificate signing requests. PEM files are the most common format for X.509 certificates and private keys used in TLS configurations.' },
  { term: 'POODLE', fullName: 'Padding Oracle on Downgraded Legacy Encryption', definition: 'A man-in-the-middle attack that exploits the SSL 3.0 protocol\'s CBC mode padding, allowing attackers to decrypt secure connections. The POODLE attack was a key driver for the deprecation of SSL 3.0 and highlights why supporting outdated protocol versions creates vulnerability.' },
  { term: 'POP3', fullName: 'Post Office Protocol 3', definition: 'A protocol used by email clients to retrieve messages from a mail server, downloading and typically deleting them from the server. POP3 should be secured using TLS (POP3S on port 995) and should be replaced with IMAP where multi-device access is needed.' },
  { term: 'PTZ', fullName: 'Pan-Tilt-Zoom', definition: 'A type of camera that can be remotely controlled to pan, tilt, and zoom, commonly used in physical security surveillance systems. PTZ cameras and surveillance systems must be secured against unauthorized access through strong credentials and network segmentation.' },
  { term: 'RA', fullName: 'Registration Authority', definition: 'An entity in a PKI that verifies the identity of certificate applicants on behalf of a Certificate Authority before certificates are issued. The RA is a critical component of certificate issuance integrity, as compromised verification processes can lead to fraudulent certificate issuance.' },
  { term: 'RAT', fullName: 'Remote Access Trojan', definition: 'A type of malware that provides an attacker with remote administrative control over a compromised system, typically installed without the victim\'s knowledge. RATs enable persistent access, data exfiltration, keystroke logging, and lateral movement within compromised networks.' },
  { term: 'RDP', fullName: 'Remote Desktop Protocol', definition: 'A proprietary Microsoft protocol that provides a graphical interface for remote access to Windows systems. RDP is frequently targeted by attackers due to its widespread use; it should be protected by VPN, MFA, network-level authentication, and regular patching to prevent exploitation.' },
  { term: 'RTOS', fullName: 'Real-Time Operating System', definition: 'An operating system designed to process data and respond to inputs within strict timing constraints, commonly used in embedded systems and industrial control systems. RTOS security is challenging due to limited processing resources, infrequent patching, and the criticality of the systems they control.' },
  { term: 'SA', fullName: 'Security Association', definition: 'A relationship between two or more entities that establishes how they will use security services to communicate securely, defining algorithms, keys, and parameters. SAs are a core concept in IPSec and IKE, with separate SAs established for each direction of communication.' },
  { term: 'SAML', fullName: 'Security Assertion Markup Language', definition: 'An XML-based standard for exchanging authentication and authorization data between identity providers and service providers. SAML enables SSO across organizational boundaries and is widely used in enterprise and government applications for federated identity management.' },
  { term: 'SAST', fullName: 'Static Application Security Testing', definition: 'A white-box testing methodology that analyzes application source code, bytecode, or binaries for security vulnerabilities without executing the program. SAST tools are integrated into CI/CD pipelines to identify vulnerabilities such as SQL injection, buffer overflows, and insecure cryptography early in the development process.' },
  { term: 'SCADA', fullName: 'Supervisory Control and Data Acquisition', definition: 'A control system architecture that uses computers, networked data communications, and graphical user interfaces for high-level process management of industrial infrastructure. SCADA systems control critical infrastructure including power grids and water treatment facilities, making their security essential to public safety.' },
  { term: 'SED', fullName: 'Self-Encrypting Drive', definition: 'A storage device that automatically encrypts all data written to it using encryption hardware built into the drive controller. SEDs provide transparent encryption without impacting system performance and are more secure than software-based FDE as the encryption keys never leave the drive.' },
  { term: 'SFTP', fullName: 'SSH File Transfer Protocol', definition: 'A secure file transfer protocol that runs over SSH, providing encrypted file access and transfer capabilities. SFTP should replace FTP in all environments as it encrypts both credentials and data, preventing eavesdropping and man-in-the-middle attacks.' },
  { term: 'SIM', fullName: 'Subscriber Identity Module', definition: 'A smart card used in mobile devices that securely stores the international mobile subscriber identity and encryption keys for authentication on mobile networks. SIM swapping attacks, where attackers socially engineer carriers into transferring a victim\'s number to a new SIM, enable bypass of SMS-based MFA.' },
  { term: 'SNAT', fullName: 'Source Network Address Translation', definition: 'A type of NAT that modifies the source IP address of packets as they leave a network, typically used to allow multiple internal hosts to share a single public IP address. SNAT is commonly used in firewall configurations to obscure internal network topology.' },
  { term: 'SOX', fullName: 'Sarbanes-Oxley Act', definition: 'A US federal law that establishes requirements for financial reporting and internal controls for publicly traded companies, including IT security controls related to financial systems. SOX compliance requires controls over access to financial systems, audit trails, and data integrity to prevent financial fraud.' },
  { term: 'SQLI', fullName: 'SQL Injection', definition: 'An injection attack that inserts malicious SQL commands into an input field, causing the backend database to execute unintended commands that can expose, modify, or destroy data. SQL injection remains one of the most common and dangerous web vulnerabilities and is prevented through parameterized queries and input validation.' },
  { term: 'SSD', fullName: 'Solid State Drive', definition: 'A storage device that uses flash memory to store data persistently, offering faster performance than traditional hard disk drives. SSD secure erasure requires special consideration as standard overwrite techniques may not reliably erase all data due to wear leveling and over-provisioning.' },
  { term: 'SSID', fullName: 'Service Set Identifier', definition: 'The name that identifies a specific wireless local area network, broadcast by access points in beacon frames. Hiding the SSID provides minimal security (security through obscurity), as it is easily discovered by passive monitoring tools and does not replace proper authentication and encryption.' },
  { term: 'STRIDE', fullName: 'Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege', definition: 'A threat modeling framework developed by Microsoft that categorizes security threats into six categories to systematically identify risks in system design. STRIDE is used during the design phase of the SDLC to identify and mitigate security threats before implementation.' },
  { term: 'TGT', fullName: 'Ticket Granting Ticket', definition: 'A Kerberos authentication ticket issued by the Authentication Server that clients use to request service tickets from the Ticket Granting Server without re-entering credentials. TGTs have a limited lifetime and their theft (Kerberoasting, pass-the-ticket) enables attackers to impersonate users.' },
  { term: 'TOFU', fullName: 'Trust On First Use', definition: 'An authentication approach that accepts an unknown key as trusted on first connection and stores it for future verification, similar to how SSH handles new host keys. TOFU is vulnerable to MITM attacks on the first connection but provides protection against subsequent attempts.' },
  { term: 'TOR', fullName: 'The Onion Router', definition: 'An anonymity network that encrypts and routes internet traffic through multiple volunteer-operated nodes to conceal a user\'s location and usage. TOR is used by both privacy-conscious users and malicious actors to obscure their identity; detecting TOR exit node traffic is important for security monitoring.' },
  { term: 'TPM', fullName: 'Trusted Platform Module', definition: 'A dedicated microcontroller designed to secure hardware through integrated cryptographic keys, providing hardware-rooted security for measured boot, disk encryption, and credential storage. TPM 2.0 is required for Windows 11 and is a fundamental component of device attestation in zero trust architectures.' },
  { term: 'UAC', fullName: 'User Account Control', definition: 'A Windows security feature that limits application software to standard user privileges until an administrator authorizes an increase. UAC helps prevent malware from making system-wide changes without user consent, though it can be bypassed through various techniques.' },
  { term: 'UDP', fullName: 'User Datagram Protocol', definition: 'A connectionless transport layer protocol that provides fast, unreliable data transmission without establishing a connection or guaranteeing delivery. UDP-based services like DNS, NTP, and SNMP are frequently exploited in amplification DDoS attacks due to the ability to spoof source IP addresses.' },
  { term: 'UPS', fullName: 'Uninterruptible Power Supply', definition: 'A device that provides emergency power to a load when the input power source fails, protecting against power outages and surges. UPS systems are essential physical security controls that protect against data loss and hardware damage from power disruptions in data centers and server rooms.' },
  { term: 'URL Filtering', fullName: 'Uniform Resource Locator Filtering', definition: 'A security control that blocks or allows access to websites based on their URLs or categories, enforcing acceptable use policies and preventing access to malicious sites. URL filtering is a key feature of SWGs and NGFWs used to prevent users from accessing phishing sites, malware distribution points, and unauthorized content.' },
  { term: 'USB', fullName: 'Universal Serial Bus', definition: 'A standard interface for connecting peripherals to computers, widely used for data transfer and charging. USB devices present significant security risks including data exfiltration via removable media, BadUSB attacks where malicious firmware masquerades as legitimate devices, and HID attacks that emulate keyboards to execute commands.' },
  { term: 'VAPT', fullName: 'Vulnerability Assessment and Penetration Testing', definition: 'A comprehensive security testing approach that combines automated vulnerability scanning with manual penetration testing to identify and validate security weaknesses. VAPT provides a more complete picture of an organization\'s security posture than either assessment type alone.' },
  { term: 'VDI', fullName: 'Virtual Desktop Infrastructure', definition: 'A technology that hosts desktop environments on a centralized server and delivers them to end users over a network, with users accessing a virtual desktop rather than a local machine. VDI improves security by keeping data centralized (not on endpoints), enabling rapid provisioning and deprovisioning, and simplifying patch management.' },
  { term: 'VPC', fullName: 'Virtual Private Cloud', definition: 'An isolated virtual network provisioned within a public cloud environment that provides customers with logical isolation from other cloud tenants. VPC security groups, network ACLs, and flow logs are key controls for securing cloud-based workloads.' },
  { term: 'VXLAN', fullName: 'Virtual Extensible LAN', definition: 'A network virtualization technology that encapsulates Layer 2 Ethernet frames within UDP packets, enabling network overlays that span physical network boundaries. VXLAN security requires careful attention to tunnel endpoint authentication and traffic encryption to prevent unauthorized access to virtual networks.' },
  { term: 'WAAP', fullName: 'Web Application and API Protection', definition: 'A comprehensive security solution that extends traditional WAF capabilities to include API security, bot management, DDoS protection, and account takeover prevention. WAAP addresses the modern application threat landscape where APIs represent a significant and growing attack surface.' },
  { term: 'WebAuthn', fullName: 'Web Authentication', definition: 'A W3C standard that enables passwordless authentication for web applications using public key cryptography, supporting hardware security keys and platform authenticators like fingerprints. WebAuthn is the web component of FIDO2 and provides phishing-resistant authentication bound to the specific origin.' },
  { term: 'WPS', fullName: 'Wi-Fi Protected Setup', definition: 'A network security standard that allows users to easily add devices to a wireless network using a PIN or button press. WPS is vulnerable to brute-force PIN attacks due to a design flaw that effectively reduces the PIN search space to 11,000 combinations; WPS should be disabled on all wireless access points.' },
  { term: 'Zero-Day', fullName: 'Zero-Day Vulnerability', definition: 'A software security vulnerability that is unknown to the software vendor or has no available patch at the time of discovery or exploitation. Zero-day vulnerabilities are highly valuable to attackers because defenders have no time (zero days) to prepare a response before exploitation begins.' },
  { term: 'DevSecOps', fullName: 'Development, Security, and Operations', definition: 'An approach to software development that integrates security practices throughout the entire development lifecycle, making security a shared responsibility across development, security, and operations teams. DevSecOps shifts security left in the SDLC, identifying and remediating vulnerabilities earlier when they are less costly to fix.' },
  { term: 'CASB', fullName: 'Cloud Access Security Broker', definition: 'An on-premises or cloud-based security policy enforcement point placed between cloud service consumers and providers. CASBs provide visibility into cloud application usage (shadow IT), enforce data security policies, detect threats, and ensure compliance in cloud environments.' },
  { term: 'DevOps', fullName: 'Development and Operations', definition: 'A set of practices that combines software development and IT operations to shorten the development lifecycle and provide continuous delivery with high software quality. DevOps pipelines must be secured to prevent supply chain attacks, as they have privileged access to production systems.' },
  { term: 'GRC', fullName: 'Governance, Risk, and Compliance', definition: 'An integrated approach to organizational governance, enterprise risk management, and regulatory compliance that aligns IT strategy with business objectives. GRC programs ensure that security investments are directed toward managing the most significant business risks and meeting compliance obligations.' },
  { term: 'HIPAA', fullName: 'Health Insurance Portability and Accountability Act', definition: 'A US federal law that establishes national standards for protecting sensitive patient health information, requiring covered entities and business associates to implement administrative, physical, and technical safeguards. HIPAA violations can result in penalties up to $1.9 million per violation category annually and criminal charges for willful neglect.' },
  { term: 'Honeynet', fullName: 'Honey Network', definition: 'A network of honeypot systems designed to attract and observe attackers, providing intelligence on attack methods, tools, and techniques. Honeynets are used by security researchers and organizations to study threat actor behavior and develop better defenses.' },
  { term: 'Honeypot', fullName: 'Honey Pot', definition: 'A decoy computer system set up to attract cyberattackers and detect, deflect, or study hacking attempts. Honeypots provide early warning of attacks, gather threat intelligence, and can divert attackers away from real production systems.' },
  { term: 'IaC', fullName: 'Infrastructure as Code', definition: 'The practice of managing and provisioning computing infrastructure through machine-readable configuration files rather than manual processes. IaC security requires scanning templates for misconfigurations, protecting the code repository, and ensuring proper access controls to prevent unauthorized infrastructure changes.' },
  { term: 'ISAC', fullName: 'Information Sharing and Analysis Center', definition: 'A nonprofit organization that serves as a central resource for gathering, analyzing, and sharing information about cybersecurity threats within a specific industry sector. ISACs foster trust and collaboration between government and private sector organizations to improve collective defense.' },
  { term: 'Kerberos', fullName: 'Kerberos Authentication Protocol', definition: 'A network authentication protocol that uses secret-key cryptography and a trusted third party (KDC) to authenticate users and services in a network. Kerberos is the default authentication protocol in Windows Active Directory environments and is subject to attacks like Kerberoasting, golden ticket, and silver ticket attacks.' },
  { term: 'Lateral Movement', fullName: 'Lateral Movement', definition: 'A post-exploitation technique where an attacker moves from the initially compromised system to other systems within the network to gain access to additional resources and data. Lateral movement is detected and prevented through network segmentation, privileged access management, and behavioral analytics.' },
  { term: 'Phishing', fullName: 'Phishing', definition: 'A social engineering attack that uses fraudulent emails, websites, or messages that appear to come from a trusted source to trick recipients into revealing sensitive information or installing malware. Phishing is the most common initial access vector for cyberattacks and is mitigated through user awareness training, email filtering, and MFA.' },
  { term: 'Ransomware', fullName: 'Ransomware', definition: 'A type of malware that encrypts a victim\'s files and demands payment (typically cryptocurrency) in exchange for the decryption key to restore access. Ransomware defense requires regular offline backups, endpoint protection, network segmentation, and prompt patching of vulnerabilities commonly exploited for initial access.' },
  { term: 'Rootkit', fullName: 'Root Kit', definition: 'A collection of software designed to enable ongoing unauthorized access to a computer while hiding its presence from users and security tools. Rootkits operate at various levels including user space, kernel, bootloader, and firmware, with lower-level rootkits being increasingly difficult to detect and remove.' },
  { term: 'Social Engineering', fullName: 'Social Engineering', definition: 'Psychological manipulation of people into performing actions or divulging confidential information rather than exploiting technical vulnerabilities. Social engineering attacks include phishing, pretexting, baiting, and tailgating; they are mitigated through security awareness training and verification procedures.' },
  { term: 'Spear Phishing', fullName: 'Spear Phishing', definition: 'A highly targeted phishing attack directed at a specific individual or organization using personalized information to increase credibility and success rates. Spear phishing is more dangerous than generic phishing because it is tailored to the victim using information gathered through OSINT.' },
  { term: 'Supply Chain Attack', fullName: 'Supply Chain Attack', definition: 'An attack that targets a third-party vendor, supplier, or service provider to gain access to the vendor\'s customers, exploiting the trust relationship between them. The SolarWinds and Kaseya attacks demonstrated how supply chain attacks can simultaneously compromise thousands of organizations.' },
  { term: 'Threat Actor', fullName: 'Threat Actor', definition: 'An individual or group that carries out malicious activities against information systems, classified by motivation (financial, espionage, hacktivism) and capability (nation-state, criminal, script kiddie). Understanding threat actor profiles helps organizations prioritize defenses against the most likely threats.' },
  { term: 'Vishing', fullName: 'Voice Phishing', definition: 'A social engineering attack conducted over the phone where attackers impersonate legitimate entities such as banks, government agencies, or IT support to extract sensitive information. Vishing attacks increased significantly with the rise of caller ID spoofing and AI voice cloning technologies.' },
  { term: 'Watering Hole', fullName: 'Watering Hole Attack', definition: 'An attack strategy where an adversary compromises websites frequently visited by targets of interest, infecting those sites with malware to compromise visitors. Watering hole attacks are difficult to detect as they exploit trusted sites and do not require the attacker to contact victims directly.' },
  { term: 'Zero Trust', fullName: 'Zero Trust Architecture', definition: 'A security model based on the principle "never trust, always verify" that eliminates implicit trust and requires continuous verification of every user, device, and application regardless of network location. Zero Trust replaces the traditional perimeter-based security model and is implemented through strong identity verification, micro-segmentation, and least privilege access.' },
  { term: 'Zero-day', fullName: 'Zero-Day Vulnerability', definition: 'A software security vulnerability unknown to the vendor or for which no patch has been released at the time of discovery or exploitation. Attackers have an advantage because defenders have zero days to prepare a response. Mitigations include intrusion prevention systems, virtual patching via WAF/IPS, and application allow-listing while awaiting a vendor patch.' },
  { term: 'ZTA', fullName: 'Zero Trust Architecture', definition: 'The technical implementation of the Zero Trust security model, characterized by: identity-centric access control, device health verification before access, microsegmentation of resources, least privilege enforcement, continuous monitoring and re-verification, and encryption of all communications. ZTA replaces perimeter-based security models and is defined in NIST SP 800-207.' },
  { term: 'SBOM', fullName: 'Software Bill of Materials', definition: 'A formal, structured inventory of all software components, libraries, and dependencies included in a software product, analogous to a food label ingredient list. SBOMs enable rapid identification of systems affected by newly discovered component vulnerabilities (such as Log4Shell) and are increasingly required by US government agencies under executive orders on software supply chain security.' },
];
